const jobId = 'xxxxxxxx-xxxx-4xxx-yxxx-xxxxxxxxxxxx'.replace(/[xy]/g, function(c) {
  const r = Math.random() * 16 | 0;
  const v = c === 'x' ? r : (r & 0x3 | 0x8);
  return v.toString(16);
});

const body = $input.first().json.body || {};

const brand = body.brand;
const language = body.language || 'Indonesian';
const products = body.products || [];
const brandContentPillars = body.brandContentPillars || [];
const platform = body.platform;
const objective = body.objective;
const contentFormats = body.contentFormats || [];
const schedule = body.schedule || {};
const numberOfTopics = body.numberOfTopics || 10;
const additionalDirection = body.additionalDirection || '';
const imageLinks = body.imageLinks || [];

return [{
  json: {
    jobId,
    brand,
    language,
    products,
    brandContentPillars,
    platform,
    objective,
    contentFormats,
    schedule,
    scheduleFrom: schedule.from || null,
    scheduleTo: schedule.to || null,
    numberOfTopics,
    additionalDirection,
    imageLinks
  }
}];

function parseMaybeJson(value, fallback) {
  if (value === null || value === undefined) return fallback;
  if (typeof value === 'object') return value;
  try {
    return JSON.parse(value);
  } catch (_) {
    return fallback;
  }
}

function textList(values) {
  if (!Array.isArray(values) || !values.length) return 'Not specified';
  return values.join(', ');
}

function cleanBrandRow(row) {
  const brand = { ...row };

  // products_context berasal dari hasil aggregate product.
  // Jangan masukkan ke brand context supaya brand dan product tetap terpisah.
  delete brand.products_context;

  return brand;
}

const req = $('Normalize Request').first().json;
const row = $input.first().json || {};

const brandContext = cleanBrandRow(row);
const productsContext = parseMaybeJson(row.products_context, []);

const skills = [
  {
    slug: 'content-strategy',
    name: 'Content Strategy',
    content: 'Use this skill to create a strategic content plan. Topics must align with brand goals, audience needs, funnel stage, content pillars, and platform context. Prioritize topics that can educate, engage, convert, or retain. Avoid random ideas; every topic should have a clear strategic role.'
  },
  {
    slug: 'social-content',
    name: 'Social Content',
    content: 'Use this skill to make topics fit social media behavior. Match the selected platform, format, and audience expectation. Instagram/TikTok should be more visual and hook-driven, LinkedIn more professional and insight-driven, YouTube more searchable and narrative-driven, Twitter/X more concise and opinion-friendly, Facebook more community-oriented.'
  },
  {
    slug: 'ad-creative',
    name: 'Ad Creative',
    content: 'Use this skill to generate topics with strong creative angles. Include clear hooks, emotional triggers, problem-solution framing, proof, contrast, urgency, curiosity, or transformation. Topics should be easy to turn into ads, reels, carousels, captions, or campaign assets.'
  },
  {
    slug: 'marketing-ideas',
    name: 'Marketing Ideas',
    content: 'Use this skill to make the topic list useful for broader marketing growth. Consider content and SEO, social/community, partnerships, product-led growth, authority building, competitor angles, lead magnets, and campaign ideas. Make topics practical, specific, and useful for future execution.'
  },
  {
    slug: 'customer-research',
    name: 'Customer Research',
    content: 'Use this skill to ground topics in customer needs. Reflect customer pain points, objections, desired outcomes, jobs-to-be-done, decision triggers, and language customers might use. Avoid company-centric topics; prefer audience-relevant topics.'
  }
];

const skillsContext = skills
  .map((skill) => `## ${skill.name}\n${skill.content}`)
  .join('\n\n---\n\n');

return [{
  json: {
    // 1. Drag this to BRAND CONTEXT
    brand_context: brandContext,
    brand_context_text: JSON.stringify(brandContext, null, 2),

    // 2. Drag this to PRODUCT CONTEXT
    products_context: productsContext,
    products_context_text: JSON.stringify(productsContext, null, 2),

    // 3. Drag this to MARKETING SKILLS APPLIED
    skills_context: skillsContext,
    applied_skills: skills.map((skill) => ({
      slug: skill.slug,
      name: skill.name
    })),

    // Request fields tetap disediakan untuk prompt AI
    jobId: req.jobId,
    brand: req.brand,
    brandId: req.brandId,
    brandName: req.brandName,
    products: req.products,
    productIds: req.productIds,
    productNames: req.productNames,

    platform: req.platform,
    objective: req.objective,

    brandContentPillars: req.brandContentPillars,
    brandContentPillars_text: textList(req.brandContentPillars),

    contentFormats: req.contentFormats,
    contentFormats_text: textList(req.contentFormats),

    scheduleFrom: req.scheduleFrom,
    scheduleTo: req.scheduleTo,
    numberOfTopics: req.numberOfTopics,
    language: req.language,
    additionalDirection: req.additionalDirection,

    imageLinks: req.imageLinks,
    imageLinks_text: textList(req.imageLinks)
  }
}];

parameters.text:
=You are an expert social media content strategist.

Your task is to generate content topics for the selected brand and products.

Apply the following marketing skills as operating guidance.
Use them to improve content strategy, social platform fit, creative angles, ad-style hooks, customer insight, and campaign relevance.
Do not mention the skills by name in the final JSON.

MARKETING SKILLS APPLIED:
{{ $json.skills_context }}

BRAND CONTEXT:
{{ $json.brand_context_text }}

PRODUCT CONTEXT:
{{ $json.products_context_text }}

PLATFORM:
{{ $json.platform }}

OBJECTIVE:
{{ $json.objective }}

CONTENT FORMATS:
{{ $json.contentFormats_text }}

BRAND CONTENT PILLARS:
{{ $json.brandContentPillars_text }}

SCHEDULE:
{{ $json.scheduleFrom }} to {{ $json.scheduleTo }}

LANGUAGE:
{{ $json.language }}

ADDITIONAL DIRECTION:
{{ $json.additionalDirection }}

IMAGE LINKS:
{{ $json.imageLinks_text }}

CRITICAL:
- Return ONLY valid JSON
- No markdown
- No explanation
- Use the requested language
- Generate exactly {{ $json.numberOfTopics }} topics
- Generate topics that fit the selected platform
- Respect selected content formats
- Respect selected brand content pillars
- Make topics specific to the brand and product
- Avoid generic topic ideas
- publishDate must be ISO date string within the requested schedule range when possible

Required JSON:
{
  "topics": [
    {
      "title": "",
      "description": "",
      "pillar": "",
      "platform": "",
      "format": "",
      "objective": "",
      "publishDate": ""
    }
  ]
}

