function uuid() {
  return 'xxxxxxxx-xxxx-4xxx-yxxx-xxxxxxxxxxxx'.replace(/[xy]/g, (c) => {
    const r = Math.random() * 16 | 0;
    const v = c === 'x' ? r : (r & 0x3 | 0x8);
    return v.toString(16);
  });
}

function sqlLiteral(value) {
  if (value === null || value === undefined) return 'NULL';
  return `'${String(value).replace(/'/g, "''")}'`;
}

function sqlJson(value) {
  return sqlLiteral(JSON.stringify(value));
}

function sqlTextArray(values) {
  if (!Array.isArray(values) || !values.length) return 'ARRAY[]::text[]';
  return `ARRAY[${values.map(sqlLiteral).join(', ')}]::text[]`;
}

function stripCodeFence(text) {
  return String(text || '')
    .trim()
    .replace(/^```(?:json)?\s*/i, '')
    .replace(/```$/i, '')
    .trim();
}

function parseAiJson(value) {
  if (value && typeof value === 'object') return value;
  const cleaned = stripCodeFence(value);
  try {
    return JSON.parse(cleaned);
  } catch (error) {
    const first = cleaned.indexOf('{');
    const last = cleaned.lastIndexOf('}');
    if (first >= 0 && last > first) return JSON.parse(cleaned.slice(first, last + 1));
    throw error;
  }
}

function validIsoDate(value, from, to) {
  if (!value) return null;
  const d = new Date(value);
  if (Number.isNaN(d.getTime())) return null;
  if (from && d < new Date(from)) return null;
  if (to) {
    const end = new Date(to);
    end.setHours(23, 59, 59, 999);
    if (d > end) return null;
  }
  return d.toISOString();
}

const req = $('Normalize Request').first().json;
const built = $('Build Topic Context + Skills Context').first().json;
const ai = $input.first().json || {};
const raw = ai.output ?? ai.text ?? ai.response ?? ai.result ?? ai;
const parsed = parseAiJson(raw);

if (!Array.isArray(parsed.topics)) {
  throw new Error('AI output must contain a topics array');
}

const fallbackPillar = req.brandContentPillars[0] || '';
const fallbackFormat = req.contentFormats[0] || '';

const topics = parsed.topics.map((topic, index) => {
  const title = String(topic.title || '').trim();
  if (!title) throw new Error(`Topic at index ${index} is missing title`);
  return {
    id: uuid(),
    title,
    description: String(topic.description || ''),
    pillar: topic.pillar || fallbackPillar,
    platform: topic.platform || req.platform || '',
    format: topic.format || fallbackFormat,
    objective: topic.objective || req.objective || '',
    publishDate: validIsoDate(topic.publishDate, req.scheduleFrom, req.scheduleTo),
  };
});

const insertTopicsSql = `
WITH topics AS (
  SELECT value AS topic
  FROM jsonb_array_elements(${sqlJson(topics)}::jsonb)
), input_product_ids AS (
  SELECT ${sqlTextArray(req.productIds)} AS product_ids
), inserted_topics AS (
  INSERT INTO content_topics (
    id,
    workspace_id,
    brand_id,
    title,
    description,
    pillar,
    platform,
    format,
    objective,
    publish_date,
    status,
    created_at,
    updated_at
  )
  SELECT
    topic->>'id',
    ${sqlLiteral(req.workspaceId)},
    ${sqlLiteral(req.brandId)},
    topic->>'title',
    NULLIF(topic->>'description', ''),
    NULLIF(topic->>'pillar', ''),
    NULLIF(topic->>'platform', ''),
    NULLIF(topic->>'format', ''),
    NULLIF(topic->>'objective', ''),
    CASE WHEN NULLIF(topic->>'publishDate', '') IS NULL THEN NULL ELSE (topic->>'publishDate')::timestamptz END,
    'draft',
    now(),
    now()
  FROM topics
  RETURNING id, title
), inserted_relations AS (
  INSERT INTO content_topic_products (content_topic_id, product_id)
  SELECT topic->>'id', ids.product_id
  FROM topics
  CROSS JOIN input_product_ids
  CROSS JOIN LATERAL unnest(input_product_ids.product_ids) AS ids(product_id)
  ON CONFLICT (content_topic_id, product_id) DO NOTHING
  RETURNING 1
)
SELECT
  (SELECT count(*) FROM inserted_topics) AS inserted_topics,
  (SELECT count(*) FROM inserted_relations) AS inserted_relations;
`;

return [{
  json: {
    runId: req.runId,
    workspaceId: req.workspaceId,
    brandId: req.brandId,
    productIds: req.productIds,
    topics,
    topicsCount: topics.length,
    insertTopicsSql,
    applied_skills: built.applied_skills,
  }
}];

const row = $input.first()?.json;

if (!row || !row.job_id) {
  return [{
    json: {
      statusCode: 404,
      body: {
        status: 'NOT_FOUND'
      }
    }
  }];
}

if (row.status !== 'DONE') {
  return [{
    json: {
      statusCode: 200,
      body: {
        jobId: row.job_id,
        status: row.status
      }
    }
  }];
}

return [{
  json: {
    statusCode: 200,
    body: {
      jobId: row.job_id,
      status: 'DONE',
      data: {
        brandId: row.brand_id,
        brandName: row.brand_name,

        productId: Array.isArray(row.product_ids) ? row.product_ids[0] : null,
        productIds: row.product_ids || [],
        productNames: row.product_names || [],

        language: row.language,
        platform: row.platform,
        objective: row.objective,
        numberOfTopics: row.number_of_topics,
        topics: row.topics || []
      }
    }
  }
}];
